import React, { useState, useRef, useEffect } from "react";
import { Link } from "react-router-dom";

export default function Login() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [emailError, setEmailError] = useState(false);
  const [passwordError, setPasswordError] = useState(false);
  const [buttonPosition, setButtonPosition] = useState({ x: 0, y: 0 });
  const [buttonText, setButtonText] = useState("Sign In");
  const buttonRef = useRef(null);
  const containerRef = useRef(null);

  const validateForm = () => {
    let isValid = true;

    if (!email || !email.includes("@") || !email.includes(".")) {
      setEmailError(true);
      isValid = false;
    } else {
      setEmailError(false);
    }

    if (!password || password.length < 6) {
      setPasswordError(true);
      isValid = false;
    } else {
      setPasswordError(false);
    }

    return isValid;
  };

  const moveButton = () => {
    if (buttonRef.current && containerRef.current) {
      const button = buttonRef.current;
      const container = containerRef.current;
      const buttonRect = button.getBoundingClientRect();
      const containerRect = container.getBoundingClientRect();

      // Calculate new position within container
      const maxX = containerRect.width - buttonRect.width;
      const maxY = containerRect.height - buttonRect.height;

      const newX = Math.random() * maxX;
      const newY = Math.random() * maxY;

      setButtonPosition({ x: newX, y: newY });
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    if (validateForm()) {
      // Form is valid - proceed with sign in
      setButtonText("Signing In...");
      setTimeout(() => {
        alert("Form submitted successfully!");
        setButtonText("Sign In");
      }, 1000);
    } else {
      // Form is invalid - button escapes
      moveButton();
      setButtonText("❌ Complete the fields!");
      setTimeout(() => {
        setButtonText("Sign In");
      }, 1500);
    }
  };

  const handleEmailChange = (e) => {
    setEmail(e.target.value);
    if (emailError) setEmailError(false);
  };

  const handlePasswordChange = (e) => {
    setPassword(e.target.value);
    if (passwordError) setPasswordError(false);
  };

  return (
    <>
      <div 
        className="container mx-auto px-4 h-full min-h-screen"
        style={{
          background: "linear-gradient(135deg, #0a2f1f 0%, #000000 50%, #0a2f1f 100%)",
        }}
      >
        <div className="flex content-center items-center justify-center h-full min-h-screen">
          <div className="w-full lg:w-5/12 px-4">
            {/* Form Container - Transparent with rounded corners */}
            <div 
              className="relative flex flex-col min-w-0 break-words w-full mb-6 shadow-2xl border-0 overflow-hidden"
              style={{
                background: "rgba(255, 255, 255, 0.08)",
                backdropFilter: "blur(12px)",
                borderRadius: "24px",
                border: "1px solid rgba(255, 255, 255, 0.18)",
              }}
            >
              <div className="rounded-t mb-0 px-6 py-6">
                <div className="text-center mb-3">
                  <h6 className="text-white text-sm font-bold">
                    Sign in with
                  </h6>
                </div>
                <div className="btn-wrapper text-center">
                  <button
                    className="bg-white/20 backdrop-blur-sm hover:bg-white/30 text-white font-normal px-4 py-2 rounded-xl outline-none focus:outline-none mr-2 mb-1 uppercase shadow hover:shadow-md inline-flex items-center font-bold text-xs ease-linear transition-all duration-150"
                    type="button"
                  >
                    <img
                      alt="..."
                      className="w-5 mr-1"
                      src={require("assets/img/github.svg").default}
                    />
                    Github
                  </button>
                  <button
                    className="bg-white/20 backdrop-blur-sm hover:bg-white/30 text-white font-normal px-4 py-2 rounded-xl outline-none focus:outline-none mr-1 mb-1 uppercase shadow hover:shadow-md inline-flex items-center font-bold text-xs ease-linear transition-all duration-150"
                    type="button"
                  >
                    <img
                      alt="..."
                      className="w-5 mr-1"
                      src={require("assets/img/google.svg").default}
                    />
                    Google
                  </button>
                </div>
                <hr className="mt-6 border-b-1 border-white/20" />
              </div>

              <div className="flex-auto px-4 lg:px-10 py-10 pt-0">
                <div className="text-white/60 text-center mb-3 font-bold">
                  <small>Or sign in with credentials</small>
                </div>

                <form onSubmit={handleSubmit}>
                  <div className="relative w-full mb-4">
                    <label className="block uppercase text-white/70 text-xs font-bold mb-2">
                      Email
                    </label>
                    <input
                      type="email"
                      value={email}
                      onChange={handleEmailChange}
                      className={`
                        px-3 py-3 placeholder-white/40 text-white 
                        rounded-2xl text-sm shadow focus:outline-none 
                        focus:ring-2 focus:ring-green-500 w-full 
                        transition-all duration-150
                        ${emailError 
                          ? "bg-red-500/20 border-2 border-red-500/50" 
                          : "bg-white/10 border border-white/20"}
                      `}
                      style={{ backdropFilter: "blur(8px)" }}
                      placeholder="your@email.com"
                    />
                    {emailError && (
                      <p className="text-red-400 text-xs mt-1 animate-pulse">
                        ⚠️ Please enter a valid email address
                      </p>
                    )}
                  </div>

                  <div className="relative w-full mb-4">
                    <label className="block uppercase text-white/70 text-xs font-bold mb-2">
                      Password
                    </label>
                    <input
                      type="password"
                      value={password}
                      onChange={handlePasswordChange}
                      className={`
                        px-3 py-3 placeholder-white/40 text-white 
                        rounded-2xl text-sm shadow focus:outline-none 
                        focus:ring-2 focus:ring-green-500 w-full 
                        transition-all duration-150
                        ${passwordError 
                          ? "bg-red-500/20 border-2 border-red-500/50" 
                          : "bg-white/10 border border-white/20"}
                      `}
                      style={{ backdropFilter: "blur(8px)" }}
                      placeholder="••••••••"
                    />
                    {passwordError && (
                      <p className="text-red-400 text-xs mt-1 animate-pulse">
                        ⚠️ Password must be at least 6 characters
                      </p>
                    )}
                  </div>

                  <div>
                    <label className="inline-flex items-center cursor-pointer">
                      <input
                        id="customCheckLogin"
                        type="checkbox"
                        className="form-checkbox rounded text-green-500 ml-1 w-5 h-5 bg-white/20 border-white/30"
                      />
                      <span className="ml-2 text-sm font-semibold text-white/70">
                        Remember me
                      </span>
                    </label>
                  </div>

                  {/* Button Container with moving button effect */}
                  <div 
                    ref={containerRef}
                    className="relative text-center mt-6 min-h-[60px]"
                  >
                    <button
                      ref={buttonRef}
                      type="submit"
                      className="bg-gradient-to-r from-green-700 to-green-900 hover:from-green-600 hover:to-green-800 text-white font-bold uppercase px-6 py-3 rounded-2xl shadow-xl hover:shadow-2xl outline-none focus:outline-none w-full ease-linear transition-all duration-300 relative"
                      style={{
                        transform: `translate(${buttonPosition.x}px, ${buttonPosition.y}px)`,
                        transition: "transform 0.3s ease-in-out",
                      }}
                    >
                      {buttonText}
                    </button>
                  </div>
                </form>
              </div>
            </div>

            <div className="flex flex-wrap mt-6 relative">
              <div className="w-1/2">
                <Link 
                  to="/auth/forget"
                  className="text-green-300 hover:text-green-200 transition-colors"
                >
                  <small>Forgot password?</small>
                </Link>
              </div>
              <div className="w-1/2 text-right">
                <Link to="/auth/register" className="text-green-300 hover:text-green-200 transition-colors">
                  <small>Create new account</small>
                </Link>
              </div>
            </div>
          </div>
        </div>
      </div>
    </>
  );
}
